Consider the following C program:
#include<stdio.h>
int main() {
    static int a[] = {10, 20, 30, 40, 50};
    static int *p[] = {a, a+3, a+4, a+1, a+2};
    int **ptr = p;
    ptr++;
    printf("%d%d", ptr-p, **ptr);
}
The output of the program is _______.
A. 140
B. 110
C. 240
D. 230

Consider the following C code:
#include<stdio.h>
int *assignval (int *x, int val) {
    *x = val;
    return x;
}
void main () {
    int *x = malloc(sizeof(int));
    if (NULL == x) return;
    x = assignval (x, 0);
    if (x) {
        x = (int *)malloc(sizeof(int));
        if (NULL == x) return;
        x = assignval (x, 10);
    }
    printf("%d\n", *x);
    free(x);
}
The code suffers from which one of the following problems:
A. compiler error as the return of malloc is not typecast appropriately
B. compiler error because the comparison should be made as x == NULL and not NULL == x
C. compiles successfully but execution may result in a dangling pointer
D. compiles successfully but execution may result in memory leak

